parameters.jsCode:
let rawText = "";

// FORMAT 1
if ($input.item.json.text) {

  rawText = $input.item.json.text;

}

// FORMAT 2
else if (
  $input.item.json.response &&
  $input.item.json.response.generations
) {

  rawText =
    $input.item.json.response.generations[0][0].text;

}

// CLEAN RESPONSE
const cleaned = rawText
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .replace(/json/g, "")
  .trim();

// PARSE JSON
const parsed = JSON.parse(cleaned);

// RETURN CLEAN DATA
return {
  json: parsed
};

